function has(n){var t={};return"numbers"==n||"digits"==n||"nums"==n?"(?=.*[0-9])":"letters"==n||"chars"==n?"(?=.*[a-zA-Z])":"telephone"==n||"phone"==n?"/^s*(?:+?(d{1,3}))?([-. (]*(d{3})[-. )]*)?((d{3})[-. ]*(d{2,4})(?:[-.x ]*(d+))?)s*$/gm":"email"==n||"e-mail"==n?'/^(([^<>()[]\\.,;:s@"]+(.[^<>()[]\\.,;:s@"]+)*)|(".+"))@(([[0-9]{1,3}.[0-9]{1,3}.[0-9]{1,3}.[0-9]{1,3}])|(([a-zA-Z-0-9]+.)+[a-zA-Z]{2,}))$/':n.match(".*\\bsite\\b.*")?"https?://(www.)?[-a-zA-Z0-9@:%._+~#=]{2,256}.[a-z]{2,6}\b([-a-zA-Z0-9@:%_+.~#?&//=]*)":t}function hasString(n){return"(?=.*\\b"+n+"\\b.*)"}function notString(n){return"(?=^(?!.*"+n+").*$)"}function not(n){var t={};return"numbers"==n?"(?=.*^([^0-9]*)$)":"letters"==n?"(?=.*^([^a-zA-Z]*)$)":t}function contains(n){return has(n),n}function includes(n){return has(n),n}function string(n){return hasString(n),n}function no(n){return not(n),n}function noString(n){return notString(n),n}
